function arrayOfStringToDataArray(astr) {
	function adjust(c) {
        const v = c.charCodeAt(0);
        return v>1  ? v-2 : v + 65534;
	}
    const temp = astr.split("").map(adjust);
    // don't adjust the first value since that's the version number
    temp[0] = astr.charCodeAt(0);
    return temp;
}

function sToE(s) {
	const e = document.createElement('span');
	e.classList.add('s');
	e.innerText = s;
	return e;
}

